package com.shecancode.product.controller; import com.shecancode.product.model.Category; import com.shecancode.product.repo.CategoryRepository; import org.springframework.web.bind.annotation.*; import java.util.List; @RestController @RequestMapping("/api/categories") public class CategoryController { private final CategoryRepository repo; public CategoryController(CategoryRepository r){repo=r;} @GetMapping public List<Category> list(){return repo.findAll();} @PostMapping public Category create(@RequestBody Category c){return repo.save(c);} }